import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { userAPI } from '../api/api';
import { useTranslation } from 'react-i18next';
import toast from 'react-hot-toast';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { 
  faGear, 
  faFileContract, 
  faShieldHalved, 
  faCookieBite, 
  faEnvelope, 
  faCircleInfo,
  faBell,
  faCartShopping,
  faTag,
  faLock,
  faFlask
} from '@fortawesome/free-solid-svg-icons';
import '../styles/settings-mobile.css';

export default function SettingsPage() {
  const { user, updateUser } = useAuth();
  const { theme: currentTheme, setTheme: applyTheme } = useTheme();
  const { t, i18n } = useTranslation();
  const [tab, setTab] = useState('profile');
  const [profileForm, setProfileForm] = useState({ 
    fullName: user?.fullName || '', 
    phone: user?.phone || '' 
  });
  const [pwForm, setPwForm] = useState({ 
    currentPassword: '', 
    newPassword: '', 
    confirm: '' 
  });
  const [saving, setSaving] = useState(false);
  const [expandedPolicy, setExpandedPolicy] = useState(null);
  const [pushPermission, setPushPermission] = useState('default');
  const [pushSubSettings, setPushSubSettings] = useState({
    orderUpdates: true,
    promotions: false,
    securityAlerts: true
  });

  // Check push notification permission on mount
  useEffect(() => {
    if ('Notification' in window) {
      setPushPermission(Notification.permission);
    }
  }, []);

  const saveProfile = async () => {
    setSaving(true);
    try {
      const res = await userAPI.updateProfile(profileForm);
      updateUser(res.data.data);
      toast.success(t('settings.profileSection.profileUpdated'));
    } catch (e) { 
      toast.error(e.response?.data?.message || t('settings.profileSection.failed')); 
    }
    setSaving(false);
  };

  const toggleSetting = async (key, value = null) => {
    const newVal = value !== null ? value : !user[key];
    try {
      const res = await userAPI.updateSettings({ [key]: newVal });
      updateUser(res.data.data);
      toast.success(t('settings.notificationsSection.settingUpdated'));
    } catch { 
      toast.error(t('settings.notificationsSection.failedUpdate')); 
    }
  };

  const togglePushSubSetting = async (key) => {
    const newVal = !pushSubSettings[key];
    setPushSubSettings(prev => ({ ...prev, [key]: newVal }));
    try {
      const res = await userAPI.updateSettings({ 
        pushNotificationPreferences: { ...pushSubSettings, [key]: newVal }
      });
      updateUser(res.data.data);
      toast.success(t('settings.notificationsSection.settingUpdated'));
    } catch { 
      setPushSubSettings(prev => ({ ...prev, [key]: !newVal }));
      toast.error(t('settings.notificationsSection.failedUpdate')); 
    }
  };

  const requestPushPermission = async () => {
    if (!('Notification' in window)) {
      toast.error(t('settings.notificationsSection.pushNotSupported'));
      return;
    }

    try {
      const permission = await Notification.requestPermission();
      setPushPermission(permission);

      if (permission === 'granted') {
        toast.success(t('settings.notificationsSection.pushEnabled'));
      } else if (permission === 'denied') {
        toast.error(t('settings.notificationsSection.pushDenied'));
      }
    } catch (err) {
      console.error('Push permission error:', err);
      toast.error(t('settings.notificationsSection.pushError'));
    }
  };

  const sendTestNotification = async () => {
    try {
      await userAPI.sendTestPush();
      toast.success(t('settings.notificationsSection.testPushSent'));
    } catch {
      toast.error(t('settings.notificationsSection.testPushFailed'));
    }
  };

  const changeTheme = async (theme) => {
    applyTheme(theme);
    try {
      const res = await userAPI.updateSettings({ theme });
      updateUser(res.data.data);
      toast.success(t('settings.appearanceSection.themeUpdated'));
    } catch { 
      toast.error(t('settings.profileSection.failed')); 
    }
  };

  const changeLanguage = async (lang) => {
    i18n.changeLanguage(lang);
    localStorage.setItem('appLanguage', lang);
    try {
      const res = await userAPI.updateSettings({ language: lang });
      updateUser(res.data.data);
      toast.success(t('settings.appearanceSection.languageUpdated'));
    } catch { 
      toast.error(t('settings.notificationsSection.failedUpdate')); 
    }
  };

  const changePassword = async () => {
    if (pwForm.newPassword !== pwForm.confirm) { 
      toast.error(t('settings.securitySection.passwordsMismatch')); 
      return; 
    }
    if (pwForm.newPassword.length < 6) { 
      toast.error(t('settings.securitySection.passwordTooShort')); 
      return; 
    }
    setSaving(true);
    try {
      await userAPI.changePassword({ 
        currentPassword: pwForm.currentPassword, 
        newPassword: pwForm.newPassword 
      });
      toast.success(t('settings.securitySection.passwordChanged'));
      setPwForm({ currentPassword: '', newPassword: '', confirm: '' });
    } catch (e) { 
      toast.error(e.response?.data?.message || t('settings.profileSection.failed')); 
    }
    setSaving(false);
  };

  const togglePolicy = (id) => {
    setExpandedPolicy(expandedPolicy === id ? null : id);
  };

  const policies = [
    {
      id: 'terms',
      icon: faFileContract,
      title: t('settings.policiesSection.terms.title'),
      lastUpdated: '2026-01-15',
      content: t('settings.policiesSection.terms.content')
    },
    {
      id: 'privacy',
      icon: faShieldHalved,
      title: t('settings.policiesSection.privacy.title'),
      lastUpdated: '2026-02-01',
      content: t('settings.policiesSection.privacy.content')
    },
    {
      id: 'cookie',
      icon: faCookieBite,
      title: t('settings.policiesSection.cookie.title'),
      lastUpdated: '2025-12-10',
      content: t('settings.policiesSection.cookie.content')
    },
    {
      id: 'refund',
      icon: faEnvelope,
      title: t('settings.policiesSection.refund.title'),
      lastUpdated: '2026-01-20',
      content: t('settings.policiesSection.refund.content')
    },
  ];

  const tabs = [
    { id: 'profile', label: t('settings.profile') },
    { id: 'notifications', label: t('settings.notifications') },
    { id: 'appearance', label: t('settings.appearance') },
    { id: 'security', label: t('settings.security') },
    { id: 'policies', label: t('settings.termsPolicies') },
  ];

  // Helper component for toggle switch
  const ToggleSwitch = ({ enabled, onToggle, disabled = false, size = 'default' }) => (
    <button 
      className={`toggle ${enabled ? 'active' : ''} ${disabled ? 'disabled' : ''} ${size}`}
      onClick={onToggle}
      disabled={disabled}
      aria-pressed={enabled}
      type="button"
    />
  );

  return (
    <div className="page-container">
      <h1 className="page-title">
        <FontAwesomeIcon icon={faGear} className="me-2 settings-icon" />
        {t('settings.title')}
      </h1>

      <div className="settings-tabs" role="tablist">
        {tabs.map(tb => (
          <button 
            key={tb.id} 
            className={`settings-tab ${tab === tb.id ? 'active' : ''}`} 
            onClick={() => setTab(tb.id)}
            role="tab"
            aria-selected={tab === tb.id}
            type="button"
          >
            {tb.label}
          </button>
        ))}
      </div>

      <div className="settings-section">
        {/* ===== PROFILE TAB ===== */}
        {tab === 'profile' && (
          <>
            <div className="form-group" style={{ marginBottom: 16 }}>
              <label htmlFor="fullName">{t('settings.profileSection.fullName')}</label>
              <input 
                id="fullName"
                value={profileForm.fullName} 
                onChange={e => setProfileForm({ ...profileForm, fullName: e.target.value })} 
                placeholder={t('settings.profileSection.fullNamePlaceholder')}
              />
            </div>
            <div className="form-group" style={{ marginBottom: 16 }}>
              <label htmlFor="email">{t('settings.profileSection.email')}</label>
              <input 
                id="email"
                value={user?.email || ''} 
                disabled 
                style={{ opacity: 0.6 }} 
              />
              <span style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                {t('settings.profileSection.emailCantChange')}
              </span>
            </div>
            <div className="form-group" style={{ marginBottom: 24 }}>
              <label htmlFor="phone">{t('settings.profileSection.phone')}</label>
              <input 
                id="phone"
                value={profileForm.phone} 
                onChange={e => setProfileForm({ ...profileForm, phone: e.target.value })} 
                placeholder={t('settings.profileSection.phonePlaceholder')} 
                type="tel"
              />
            </div>
            <button 
              className="btn btn-primary" 
              onClick={saveProfile} 
              disabled={saving}
              type="button"
            >
              {saving ? t('settings.profileSection.saving') : t('settings.profileSection.saveChanges')}
            </button>
          </>
        )}

        {/* ===== NOTIFICATIONS TAB ===== */}
        {tab === 'notifications' && (
          <>
            {/* Email Notifications */}
            <div className="setting-row">
              <div className="setting-info">
                <h4>{t('settings.notificationsSection.emailNotifications')}</h4>
                <p>{t('settings.notificationsSection.emailNotificationsDesc')}</p>
              </div>
              <ToggleSwitch 
                enabled={user?.emailNotifications} 
                onToggle={() => toggleSetting('emailNotifications')} 
              />
            </div>

            {/* Push Notifications Header */}
            <div style={{ 
              padding: '16px 0', 
              borderBottom: '1px solid var(--border-color)',
              marginBottom: 16
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                <FontAwesomeIcon icon={faBell} style={{ color: 'var(--accent-color, #7c3aed)' }} />
                <h3 style={{ margin: 0, fontSize: '1.05rem', fontWeight: 600 }}>
                  {t('settings.notificationsSection.pushNotifications')}
                </h3>
              </div>
              <p style={{ margin: '4px 0 12px', color: 'var(--text-muted)', fontSize: '0.9rem' }}>
                {t('settings.notificationsSection.pushNotificationsDesc')}
              </p>

              {/* Permission Status */}
              <div style={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: 8, 
                marginBottom: 12,
                flexWrap: 'wrap'
              }}>
                <span style={{ 
                  fontSize: '0.85rem',
                  padding: '4px 10px',
                  borderRadius: '20px',
                  background: pushPermission === 'granted' ? 'rgba(34,197,94,0.15)' : 
                             pushPermission === 'denied' ? 'rgba(239,68,68,0.15)' : 
                             'rgba(107,114,128,0.15)',
                  color: pushPermission === 'granted' ? '#22c55e' : 
                         pushPermission === 'denied' ? '#ef4444' : 
                         '#6b7280',
                  fontWeight: 500
                }}>
                  {pushPermission === 'granted' ? t('settings.notificationsSection.pushAllowed') : 
                   pushPermission === 'denied' ? t('settings.notificationsSection.pushBlocked') : 
                   t('settings.notificationsSection.pushDefault')}
                </span>

                {pushPermission !== 'granted' && (
                  <button 
                    className="btn btn-sm btn-secondary"
                    onClick={requestPushPermission}
                    style={{ padding: '4px 12px', fontSize: '0.8rem' }}
                    type="button"
                  >
                    {t('settings.notificationsSection.enablePush')}
                  </button>
                )}
              </div>

              {/* Main Push Toggle */}
              {pushPermission === 'granted' && (
                <div className="setting-row" style={{ alignItems: 'center' }}>
                  <div className="setting-info" style={{ flex: 1 }}>
                    <strong style={{ fontSize: '0.95rem' }}>
                      {t('settings.notificationsSection.receivePush')}
                    </strong>
                  </div>
                  <ToggleSwitch 
                    enabled={user?.pushNotifications} 
                    onToggle={() => toggleSetting('pushNotifications')} 
                  />
                </div>
              )}
            </div>

            {/* Push Notification Sub-settings */}
            {pushPermission === 'granted' && user?.pushNotifications && (
              <div style={{ 
                paddingLeft: 12, 
                borderLeft: '2px solid var(--border-color)',
                marginBottom: 20
              }}>
                <p style={{ 
                  fontSize: '0.85rem', 
                  color: 'var(--text-muted)', 
                  marginBottom: 12,
                  fontStyle: 'italic'
                }}>
                  {t('settings.notificationsSection.customizePushTypes')}
                </p>

                {/* Order Updates */}
                <div className="setting-row" style={{ padding: '8px 0' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <FontAwesomeIcon icon={faCartShopping} style={{ color: '#3b82f6', width: 16 }} />
                    <div>
                      <div style={{ fontWeight: 500, fontSize: '0.9rem' }}>
                        {t('settings.notificationsSection.orderUpdates')}
                      </div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                        {t('settings.notificationsSection.orderUpdatesDesc')}
                      </div>
                    </div>
                  </div>
                  <ToggleSwitch 
                    enabled={pushSubSettings.orderUpdates} 
                    onToggle={() => togglePushSubSetting('orderUpdates')}
                    size="small"
                  />
                </div>

                {/* Promotions */}
                <div className="setting-row" style={{ padding: '8px 0' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <FontAwesomeIcon icon={faTag} style={{ color: '#f59e0b', width: 16 }} />
                    <div>
                      <div style={{ fontWeight: 500, fontSize: '0.9rem' }}>
                        {t('settings.notificationsSection.promotions')}
                      </div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                        {t('settings.notificationsSection.promotionsDesc')}
                      </div>
                    </div>
                  </div>
                  <ToggleSwitch 
                    enabled={pushSubSettings.promotions} 
                    onToggle={() => togglePushSubSetting('promotions')}
                    size="small"
                  />
                </div>

                {/* Security Alerts */}
                <div className="setting-row" style={{ padding: '8px 0' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <FontAwesomeIcon icon={faLock} style={{ color: '#ef4444', width: 16 }} />
                    <div>
                      <div style={{ fontWeight: 500, fontSize: '0.9rem' }}>
                        {t('settings.notificationsSection.securityAlerts')}
                      </div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                        {t('settings.notificationsSection.securityAlertsDesc')}
                      </div>
                    </div>
                  </div>
                  <ToggleSwitch 
                    enabled={pushSubSettings.securityAlerts} 
                    onToggle={() => togglePushSubSetting('securityAlerts')}
                    size="small"
                  />
                </div>

                {/* Test Notification Button */}
                <div style={{ marginTop: 16, paddingTop: 12, borderTop: '1px dashed var(--border-color)' }}>
                  <button 
                    className="btn btn-sm btn-secondary"
                    onClick={sendTestNotification}
                    style={{ display: 'flex', alignItems: 'center', gap: 6 }}
                    type="button"
                  >
                    <FontAwesomeIcon icon={faFlask} />
                    {t('settings.notificationsSection.testPushNotification')}
                  </button>
                </div>
              </div>
            )}

            {/* Helper text for push notifications */}
            <div style={{ 
              marginTop: 8, 
              padding: '12px', 
              background: 'var(--bg-secondary, rgba(124,58,237,0.06))', 
              borderRadius: 8,
              fontSize: '0.82rem',
              color: 'var(--text-muted)',
              lineHeight: 1.5
            }}>
              <FontAwesomeIcon icon={faCircleInfo} style={{ marginRight: 6, color: 'var(--accent-color, #7c3aed)' }} />
              {t('settings.notificationsSection.pushHelpText')}
            </div>
          </>
        )}

        {/* ===== APPEARANCE TAB ===== */}
        {tab === 'appearance' && (
          <>
            <div className="setting-row">
              <div className="setting-info">
                <h4>{t('settings.appearanceSection.theme')}</h4>
                <p>{t('settings.appearanceSection.themeDesc')}</p>
              </div>
              <div style={{ display: 'flex', gap: 8 }}>
                {['dark', 'light', 'system'].map(thm => (
                  <button 
                    key={thm} 
                    className={`btn btn-sm ${currentTheme === thm ? 'btn-primary' : 'btn-secondary'}`}
                    onClick={() => changeTheme(thm)}
                    type="button"
                  >
                    {t(`settings.appearanceSection.${thm}`)}
                  </button>
                ))}
              </div>
            </div>
            <div className="setting-row">
              <div className="setting-info">
                <h4>{t('settings.appearanceSection.language')}</h4>
                <p>{t('settings.appearanceSection.languageDesc')}</p>
              </div>
              <select
                value={i18n.language}
                style={{ width: 'auto', padding: '8px 16px', borderRadius: '6px' }}
                onChange={(e) => changeLanguage(e.target.value)}
              >
                <option value="en">English</option>
                <option value="es">Español</option>
                <option value="fr">Français</option>
                <option value="de">Deutsch</option>
                <option value="ja">日本語</option>
              </select>
            </div>
          </>
        )}

        {/* ===== SECURITY TAB ===== */}
        {tab === 'security' && (
          <>
            <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: 16 }}>
              {t('settings.securitySection.changePassword')}
            </h3>
            <div className="form-group" style={{ marginBottom: 16 }}>
              <label htmlFor="currentPassword">{t('settings.securitySection.currentPassword')}</label>
              <input 
                id="currentPassword"
                type="password" 
                value={pwForm.currentPassword}
                onChange={e => setPwForm({ ...pwForm, currentPassword: e.target.value })} 
                placeholder="••••••••"
              />
            </div>
            <div className="form-group" style={{ marginBottom: 16 }}>
              <label htmlFor="newPassword">{t('settings.securitySection.newPassword')}</label>
              <input 
                id="newPassword"
                type="password" 
                value={pwForm.newPassword}
                onChange={e => setPwForm({ ...pwForm, newPassword: e.target.value })}
                placeholder={t('settings.securitySection.newPasswordPlaceholder')}
              />
            </div>
            <div className="form-group" style={{ marginBottom: 24 }}>
              <label htmlFor="confirmPassword">{t('settings.securitySection.confirmPassword')}</label>
              <input 
                id="confirmPassword"
                type="password" 
                value={pwForm.confirm}
                onChange={e => setPwForm({ ...pwForm, confirm: e.target.value })}
                placeholder={t('settings.securitySection.confirmPasswordPlaceholder')}
              />
            </div>
            <button 
              className="btn btn-primary" 
              onClick={changePassword} 
              disabled={saving}
              type="button"
            >
              {saving ? t('settings.securitySection.changingPassword') : t('settings.securitySection.changePassword')}
            </button>
          </>
        )}

        {/* ===== POLICIES TAB ===== */}
        {tab === 'policies' && (
          <>
            <div style={{ marginBottom: 20 }}>
              <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', margin: 0 }}>
                {t('settings.policiesSection.policiesDesc')}
              </p>
            </div>

            {policies.map(policy => (
              <div key={policy.id} className="policy-card" style={{
                border: '1px solid var(--border-color)',
                borderRadius: 10,
                marginBottom: 12,
                overflow: 'hidden',
                transition: 'box-shadow 0.2s ease',
              }}>
                <button
                  onClick={() => togglePolicy(policy.id)}
                  style={{
                    width: '100%',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    padding: '16px 20px',
                    background: 'transparent',
                    border: 'none',
                    cursor: 'pointer',
                    color: 'var(--text-primary)',
                    textAlign: 'left',
                  }}
                  aria-expanded={expandedPolicy === policy.id}
                  type="button"
                >
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <FontAwesomeIcon icon={policy.icon} style={{ fontSize: '1.1rem', color: 'var(--accent-color, #7c3aed)', width: 20 }} />
                    <div>
                      <h4 style={{ margin: 0, fontSize: '0.95rem', fontWeight: 600 }}>{policy.title}</h4>
                      <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                        {t('settings.policiesSection.lastUpdated')}: {policy.lastUpdated}
                      </span>
                    </div>
                  </div>
                  <span style={{
                    fontSize: '1.1rem',
                    transition: 'transform 0.2s ease',
                    transform: expandedPolicy === policy.id ? 'rotate(180deg)' : 'rotate(0deg)',
                  }}>
                    ▼
                  </span>
                </button>

                {expandedPolicy === policy.id && (
                  <div style={{
                    padding: '0 20px 20px 52px',
                    fontSize: '0.88rem',
                    lineHeight: 1.7,
                    color: 'var(--text-secondary)',
                    whiteSpace: 'pre-line',
                  }}>
                    {policy.content}
                  </div>
                )}
              </div>
            ))}

            <div style={{
              marginTop: 24,
              padding: '14px 18px',
              background: 'var(--bg-secondary, rgba(124,58,237,0.06))',
              borderRadius: 10,
              display: 'flex',
              alignItems: 'flex-start',
              gap: 12,
            }}>
              <FontAwesomeIcon icon={faCircleInfo} style={{ color: 'var(--accent-color, #7c3aed)', marginTop: 2 }} />
              <p style={{ margin: 0, fontSize: '0.84rem', color: 'var(--text-muted)', lineHeight: 1.6 }}>
                {t('settings.policiesSection.policiesContact')}
              </p>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
